import { useNProgress } from "@tanem/react-nprogress";
import { useMutation } from "@tanstack/react-query";
import {
  CheckIcon,
  CopyIcon,
  IdCardLanyardIcon,
  ShapesIcon,
} from "lucide-react";
import { useEffect, useMemo, useRef, useState, useTransition } from "react";
import { FormProvider, useForm } from "react-hook-form";
import { Button } from "zudoku/ui/Button.js";
import { Collapsible, CollapsibleContent } from "zudoku/ui/Collapsible.js";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "zudoku/ui/Select.js";
import { TooltipProvider } from "zudoku/ui/Tooltip.js";
import { useApiIdentities } from "../../../components/context/ZudokuContext.js";
import { useHotkey } from "../../../hooks/useHotkey.js";
import { cn } from "../../../util/cn.js";
import { useCopyToClipboard } from "../../../util/useCopyToClipboard.js";
import { useLatest } from "../../../util/useLatest.js";
import type {
  MediaTypeObject,
  SecuritySchemeIn,
  SecuritySchemeType,
} from "../graphql/graphql.js";
import { useSelectedServer } from "../state.js";
import { AuthorizeDialog } from "./AuthorizeDialog.js";
import BodyPanel from "./BodyPanel.js";
import { buildRequestBody } from "./buildRequestBody.js";
import {
  CollapsibleHeader,
  CollapsibleHeaderTrigger,
} from "./CollapsibleHeader.js";
import { NO_IDENTITY, SECURITY_SCHEME_PREFIX } from "./constants.js";
import { createUrl } from "./createUrl.js";
import { extractFileName, isBinaryContentType } from "./fileUtils.js";
import { Headers } from "./Headers.js";
import { IdentityDialog } from "./IdentityDialog.js";
import IdentitySelector from "./IdentitySelector.js";
import { PathParams } from "./PathParams.js";
import { QueryParams } from "./QueryParams.js";
import { useIdentityStore } from "./rememberedIdentity.js";
import { UrlPath } from "./request-panel/UrlPath.js";
import { UrlQueryParams } from "./request-panel/UrlQueryParams.js";
import RequestLoginDialog from "./RequestLoginDialog.js";
import { ResultPanel } from "./result-panel/ResultPanel.js";
import {
  applySecurityCredentials,
  getSecurityLockedHeaders,
  getSecurityQueryParams,
  useSecurityCredentialsStore,
} from "./securityCredentialsStore.js";
import { useRememberSkipLoginDialog } from "./useRememberSkipLoginDialog.js";

export { NO_IDENTITY, SECURITY_SCHEME_PREFIX } from "./constants.js";

export type Header = {
  name: string;
  defaultValue?: string;
  defaultActive?: boolean;
  isRequired?: boolean;
  enum?: string[];
  type?: string;
};

export type QueryParam = {
  name: string;
  defaultValue?: string;
  defaultActive?: boolean;
  isRequired?: boolean;
  enum?: string[];
  type?: string;
  style?: string;
  explode?: boolean;
  allowReserved?: boolean;
};

export type PathParam = {
  name: string;
  defaultValue?: string;
  isRequired?: boolean;
};

export type PlaygroundForm = {
  body: string;
  bodyMode?: "text" | "file" | "multipart" | "urlencoded";
  file?: File | null;
  multipartFormFields: Array<{
    name: string;
    value: File | string;
    active: boolean;
  }>;
  urlencodedFormFields: Array<{
    name: string;
    value: string;
    active: boolean;
  }>;
  queryParams: Array<{
    name: string;
    value: string;
    active: boolean;
    enum?: string[];
    type?: string;
    style?: string;
    explode?: boolean;
    allowReserved?: boolean;
  }>;
  pathParams: Array<{ name: string; value: string }>;
  headers: Array<{
    name: string;
    value: string;
    active: boolean;
    enum?: string[];
  }>;
  identity?: string;
};

export type PlaygroundResult = {
  status: number;
  headers: Array<[string, string]>;
  size: number;
  body: string;
  time: number;
  isBinary?: boolean;
  fileName?: string;
  blob?: Blob;
  request: {
    method: string;
    url: string;
    headers: Array<[string, string]>;
    body?: string;
  };
};

export type SecurityRequirementProp = {
  schemes: Array<{
    scopes: Array<string>;
    scheme: {
      name: string;
      type: SecuritySchemeType;
      description?: string | null;
      in?: SecuritySchemeIn | null;
      paramName?: string | null;
      scheme?: string | null;
      bearerFormat?: string | null;
      openIdConnectUrl?: string | null;
      flows?: {
        implicit?: {
          authorizationUrl?: string | null;
          scopes: Array<{ name: string; description: string }>;
        } | null;
        password?: {
          tokenUrl?: string | null;
          scopes: Array<{ name: string; description: string }>;
        } | null;
        clientCredentials?: {
          tokenUrl?: string | null;
          scopes: Array<{ name: string; description: string }>;
        } | null;
        authorizationCode?: {
          authorizationUrl?: string | null;
          tokenUrl?: string | null;
          scopes: Array<{ name: string; description: string }>;
        } | null;
      } | null;
    };
  }>;
};

export type PlaygroundContentProps = {
  server?: string;
  servers?: string[];
  url: string;
  method: string;
  headers?: Header[];
  queryParams?: QueryParam[];
  pathParams?: PathParam[];
  defaultBody?: string;
  examples?: MediaTypeObject[];
  security?: SecurityRequirementProp[];
  securitySchemes?: Array<{
    name: string;
    type: SecuritySchemeType;
    description?: string | null;
    in?: SecuritySchemeIn | null;
    paramName?: string | null;
    scheme?: string | null;
    bearerFormat?: string | null;
    openIdConnectUrl?: string | null;
    flows?: Record<string, unknown> | null;
  }>;
  requiresLogin?: boolean;
  onLogin?: () => void;
  onSignUp?: () => void;
};

export const Playground = ({
  server,
  servers = [],
  url,
  method,
  headers = [],
  queryParams = [],
  pathParams = [],
  defaultBody = "",
  examples,
  security,
  securitySchemes = [],
  requiresLogin = false,
  onLogin,
  onSignUp,
}: PlaygroundContentProps) => {
  const { selectedServer, setSelectedServer } = useSelectedServer(
    servers.map((url) => ({ url })),
  );
  const [showSelectIdentity, setShowSelectIdentity] = useState(false);
  const [showAuthorizeDialog, setShowAuthorizeDialog] = useState(false);
  const identities = useApiIdentities();
  const { setRememberedIdentity, getRememberedIdentity } = useIdentityStore();
  const [, startTransition] = useTransition();
  const { skipLogin, setSkipLogin } = useRememberSkipLoginDialog();
  const [isLoginDialogDismissed, setIsLoginDialogDismissed] = useState(false);
  const [showLongRunningWarning, setShowLongRunningWarning] = useState(false);
  const abortControllerRef = useRef<AbortController | undefined>(undefined);
  const latestSetRememberedIdentity = useLatest(setRememberedIdentity);
  const formRef = useRef<HTMLFormElement>(null);

  const { label: hotkeyLabel } = useHotkey("meta+enter", () => {
    formRef.current?.requestSubmit();
  });

  const pathParamOrder =
    url.match(/\{([^}]+)\}/g)?.map((match) => match.slice(1, -1)) ?? [];
  const sortedPathParams = [...pathParams].sort(
    (a, b) => pathParamOrder.indexOf(a.name) - pathParamOrder.indexOf(b.name),
  );

  const { register, control, handleSubmit, watch, setValue, ...form } =
    useForm<PlaygroundForm>({
      defaultValues: {
        body: defaultBody,
        bodyMode: "text",
        file: null,
        multipartFormFields: [],
        urlencodedFormFields: [],
        queryParams:
          queryParams.length > 0
            ? queryParams.map((param) => ({
                name: param.name,
                value: param.defaultValue ?? "",
                active: param.defaultActive ?? false,
                enum: param.enum ?? [],
                type: param.type,
                style: param.style,
                explode: param.explode,
                allowReserved: param.allowReserved,
              }))
            : [{ name: "", value: "", active: false, enum: [] }],
        pathParams: sortedPathParams.map((param) => ({
          name: param.name,
          value: param.defaultValue ?? "",
        })),
        headers:
          headers.length > 0
            ? headers.map((header) => ({
                name: header.name,
                value: header.defaultValue ?? "",
                active: header.defaultActive ?? false,
              }))
            : [{ name: "", value: "", active: false }],
        identity: getRememberedIdentity([
          NO_IDENTITY,
          ...securitySchemes.map((s) => `${SECURITY_SCHEME_PREFIX}${s.name}`),
          ...(identities.data?.map((i) => i.id) ?? []),
        ]),
      },
    });
  const identity = watch("identity");

  const authorizationFields = useMemo(
    () => identities.data?.find((i) => i.id === identity)?.authorizationFields,
    [identities.data, identity],
  );

  const securityCredentials = useSecurityCredentialsStore((s) => s.credentials);

  const selectedSchemeName = identity?.startsWith(SECURITY_SCHEME_PREFIX)
    ? identity.slice(SECURITY_SCHEME_PREFIX.length)
    : undefined;

  const securityLockedHeaders = useMemo(() => {
    const cred = selectedSchemeName
      ? securityCredentials[selectedSchemeName]
      : undefined;
    if (!selectedSchemeName || !cred) return [];
    return getSecurityLockedHeaders(security, {
      [selectedSchemeName]: cred,
    });
  }, [security, securityCredentials, selectedSchemeName]);

  useEffect(() => {
    if (identity) {
      latestSetRememberedIdentity.current(identity);
    }
  }, [latestSetRememberedIdentity, identity]);

  const queryMutation = useMutation({
    gcTime: 0,
    mutationFn: async (data: PlaygroundForm) => {
      const start = performance.now();

      const headers = new window.Headers(
        data.headers
          .filter((h) => h.name && h.active)
          .map<[string, string]>((h) => [h.name, h.value]),
      );

      const built = buildRequestBody(data);
      const body = built.body;
      switch (built.contentType.kind) {
        case "remove":
          headers.delete("Content-Type");
          break;
        case "override":
          headers.set("Content-Type", built.contentType.value);
          break;
      }

      const upperMethod = method.toUpperCase();
      const requestUrl = createUrl(server ?? selectedServer, url, data);

      const schemeName = data.identity?.startsWith(SECURITY_SCHEME_PREFIX)
        ? data.identity.slice(SECURITY_SCHEME_PREFIX.length)
        : undefined;

      const schemeCredentials = (() => {
        if (!schemeName) return {};
        const cred =
          useSecurityCredentialsStore.getState().credentials[schemeName];
        return cred ? { [schemeName]: cred } : {};
      })();

      if (schemeName) {
        for (const [key, value] of getSecurityQueryParams(
          security,
          schemeCredentials,
        )) {
          requestUrl.searchParams.set(key, value);
        }
      }

      const request = new Request(requestUrl, {
        method: upperMethod,
        headers,
        body: ["GET", "HEAD"].includes(upperMethod) ? null : body,
      });

      if (schemeName) {
        applySecurityCredentials(request, security, schemeCredentials);
      } else if (data.identity !== NO_IDENTITY) {
        await identities.data
          ?.find((i) => i.id === data.identity)
          ?.authorizeRequest(request);
      }

      const warningTimeout = setTimeout(
        () => setShowLongRunningWarning(true),
        3210,
      );
      abortControllerRef.current = new AbortController();

      abortControllerRef.current.signal.addEventListener("abort", () => {
        clearTimeout(warningTimeout);
      });

      try {
        const response = await fetch(request, {
          cache: "no-store",
          signal: abortControllerRef.current.signal,
        });

        clearTimeout(warningTimeout);
        setShowLongRunningWarning(false);

        const time = performance.now() - start;
        const url = new URL(request.url);
        const responseHeaders = Array.from(response.headers.entries());
        const contentType = response.headers.get("content-type") || "";
        const isBinary = isBinaryContentType(contentType);

        let body = "";
        let blob: Blob | undefined;
        let fileName: string | undefined;

        if (isBinary) {
          blob = await response.blob();
          fileName = extractFileName(responseHeaders, request.url);
          body = `Binary content (${contentType})`;
        } else {
          body = await response.text();
        }

        const responseSize = response.headers.get("content-length");

        let requestBody = "";

        switch (data.bodyMode) {
          case "text":
            requestBody = data.body;
            break;
          case "file":
            requestBody = `[File: ${data.file?.name ?? "Unknown"}]`;
            break;
          case "multipart":
            requestBody = "[Multipart Form Data]\n";
            requestBody += data.multipartFormFields
              ?.filter((f) => f.name && f.active)
              .map((f) =>
                f.value instanceof File
                  ? `${f.name}: [File: ${f.value.name}]`
                  : `${f.name}: ${f.value}`,
              )
              .join("\n");
            break;
          case "urlencoded":
            requestBody = typeof built.body === "string" ? built.body : "";
            break;
          default:
            requestBody = data.body;
            break;
        }

        return {
          status: response.status,
          headers: responseHeaders,
          size: responseSize ? Number(responseSize) : body.length,
          body,
          time,
          isBinary,
          fileName,
          blob,
          request: {
            method: request.method.toUpperCase(),
            url: request.url,
            headers: [
              ["Host", url.host],
              ["User-Agent", "Zudoku Playground"],
              ...Array.from(request.headers.entries()),
            ],
            body: requestBody,
          },
        } satisfies PlaygroundResult;
      } catch (error) {
        clearTimeout(warningTimeout);
        setShowLongRunningWarning(false);
        if (error instanceof TypeError) {
          throw new Error(
            "The request failed, possibly due to network issues or CORS policy.",
          );
        } else {
          throw error;
        }
      }
    },
  });

  const isRequestAnimating = queryMutation.isPending;
  const [isAnimating, setIsAnimating] = useState(false);

  useEffect(() => {
    const timer = setTimeout(() => setIsAnimating(isRequestAnimating), 100);
    return () => clearTimeout(timer);
  }, [isRequestAnimating]);

  const { isFinished, progress } = useNProgress({ isAnimating });

  useEffect(() => {
    return () => {
      abortControllerRef.current?.abort();
    };
  }, []);

  const serverSelect = (
    <div className="inline-block align-middle -translate-y-px opacity-50 hover:opacity-100 transition">
      {server ? (
        <span>{server.replace(/^https?:\/\//, "").replace(/\/$/, "")}</span>
      ) : (
        servers.length > 1 && (
          <Select
            onValueChange={(value) => {
              startTransition(() => setSelectedServer(value));
            }}
            value={selectedServer}
            defaultValue={selectedServer}
          >
            <SelectTrigger className="p-0! h-6! shadow-none border-none flex-row-reverse bg-transparent text-xs gap-0.5">
              <SelectValue />
            </SelectTrigger>
            <SelectContent>
              {servers.map((s) => (
                <SelectItem key={s} value={s}>
                  {s.replace(/^https?:\/\//, "").replace(/\/$/, "")}
                </SelectItem>
              ))}
            </SelectContent>
          </Select>
        )
      )}
    </div>
  );

  const showLogin = requiresLogin && !skipLogin && !isLoginDialogDismissed;
  const isBodySupported = ["POST", "PUT", "PATCH", "DELETE"].includes(
    method.toUpperCase(),
  );
  const [isCopied, copyToClipboard] = useCopyToClipboard();

  return (
    <FormProvider
      {...{ register, control, handleSubmit, watch, setValue, ...form }}
    >
      <TooltipProvider delayDuration={150}>
        <form
          ref={formRef}
          onKeyDown={(e) => {
            if (e.key === "Enter" && e.target instanceof HTMLInputElement) {
              e.preventDefault();
            }
          }}
          onSubmit={handleSubmit((data) => {
            if (identities.data?.length === 0 || data.identity) {
              queryMutation.mutate(data);
            } else {
              setShowSelectIdentity(true);
            }
          })}
          className="relative"
        >
          <IdentityDialog
            identities={identities.data ?? []}
            open={showSelectIdentity}
            onOpenChange={setShowSelectIdentity}
            onSubmit={({ rememberedIdentity, identity }) => {
              if (rememberedIdentity) {
                setValue("identity", identity ?? NO_IDENTITY);
              }
              setShowSelectIdentity(false);
              queryMutation.mutate({ ...form.getValues(), identity });
            }}
          />
          <RequestLoginDialog
            open={showLogin}
            setOpen={(open) => {
              if (!open) {
                setIsLoginDialogDismissed(true);
              }
            }}
            onSkip={(rememberSkip) => {
              setIsLoginDialogDismissed(true);
              if (rememberSkip) {
                setSkipLogin(true);
              }
            }}
            onSignUp={onSignUp}
            onLogin={onLogin}
          />

          <div className="grid grid-cols-[1fr_1px_1fr] text-sm">
            <div className="col-span-3 p-4 border-b flex gap-2 items-stretch">
              <div className="flex flex-1 items-stretch w-full min-h-8 border rounded-md relative overflow-hidden">
                <div className="border-r px-2 bg-muted rounded-l-md font-semibold font-mono flex items-center">
                  {method.toUpperCase()}
                </div>
                <div className="flex-1 min-w-0 px-2 font-mono text-xs break-all leading-6 flex items-center">
                  <div>
                    {serverSelect}
                    <UrlPath url={url} />
                    <UrlQueryParams />
                  </div>
                </div>
                <div className="px-1 flex items-center">
                  <Button
                    type="button"
                    onClick={() => {
                      copyToClipboard(
                        createUrl(
                          server ?? selectedServer,
                          url,
                          form.getValues(),
                        ).toString(),
                      );
                    }}
                    variant="ghost"
                    size="icon-xs"
                    aria-label="Copy URL"
                    className={cn(
                      "hover:opacity-100 transition",
                      isCopied ? "text-emerald-600 opacity-100" : "opacity-50",
                    )}
                  >
                    {isCopied ? (
                      <CheckIcon
                        className="text-green-500"
                        size={14}
                        aria-hidden="true"
                      />
                    ) : (
                      <CopyIcon size={14} aria-hidden="true" />
                    )}
                  </Button>
                </div>
              </div>

              <Button
                type="submit"
                variant={queryMutation.isPending ? "destructive" : "default"}
                onClick={(e) => {
                  if (queryMutation.isPending) {
                    abortControllerRef.current?.abort(
                      "Request cancelled by user",
                    );
                    e.preventDefault();
                  }
                }}
                className="w-18"
              >
                {queryMutation.isPending ? "Cancel" : "Send"}
              </Button>
            </div>
            <div className="relative overflow-y-auto h-[80vh]">
              {(identities.data?.length !== 0 ||
                securitySchemes.length > 0) && (
                <Collapsible defaultOpen>
                  <CollapsibleHeaderTrigger>
                    <IdCardLanyardIcon size={16} aria-hidden="true" />
                    <CollapsibleHeader>Authentication</CollapsibleHeader>
                  </CollapsibleHeaderTrigger>
                  <CollapsibleContent className="CollapsibleContent">
                    <IdentitySelector
                      value={identity}
                      identities={identities.data ?? []}
                      setValue={(value) => {
                        if (value.startsWith(SECURITY_SCHEME_PREFIX)) {
                          const schemeName = value.slice(
                            SECURITY_SCHEME_PREFIX.length,
                          );
                          if (!securityCredentials[schemeName]?.isAuthorized) {
                            setShowAuthorizeDialog(true);
                          }
                        }
                        setValue("identity", value);
                      }}
                      securitySchemes={
                        securitySchemes.length > 0 ? securitySchemes : undefined
                      }
                      securityCredentials={securityCredentials}
                      onConfigureScheme={() => setShowAuthorizeDialog(true)}
                    />
                    {selectedSchemeName && (
                      <AuthorizeDialog
                        securitySchemes={securitySchemes.filter(
                          (s) => s.name === selectedSchemeName,
                        )}
                        open={showAuthorizeDialog}
                        onOpenChange={setShowAuthorizeDialog}
                      />
                    )}
                  </CollapsibleContent>
                </Collapsible>
              )}

              {sortedPathParams.length > 0 && (
                <Collapsible defaultOpen>
                  <CollapsibleHeaderTrigger>
                    <ShapesIcon size={16} aria-hidden="true" />
                    <CollapsibleHeader>Path Parameters</CollapsibleHeader>
                  </CollapsibleHeaderTrigger>
                  <CollapsibleContent className="CollapsibleContent">
                    <PathParams url={url} control={control} />
                  </CollapsibleContent>
                </Collapsible>
              )}

              <QueryParams control={control} schemaQueryParams={queryParams} />

              <Headers
                control={control}
                schemaHeaders={headers}
                lockedHeaders={[
                  ...(authorizationFields?.headers ?? []),
                  ...securityLockedHeaders,
                ]}
              />
              {isBodySupported && <BodyPanel content={examples} />}
            </div>
            <div className="w-full bg-muted-foreground/20" />
            <ResultPanel
              queryMutation={queryMutation}
              showLongRunningWarning={showLongRunningWarning}
              isFinished={isFinished}
              progress={progress}
              tip={
                <div className="text-xs w-full">
                  <span className="text-muted-foreground">
                    Press{" "}
                    <kbd className="text-foreground border rounded m-0.5 px-1 py-0.5 capitalize">
                      {hotkeyLabel.join(" + ")}
                    </kbd>{" "}
                    to send a request
                  </span>
                </div>
              }
              onCancel={() => {
                abortControllerRef.current?.abort(
                  "Request cancelled by the user",
                );
                setShowLongRunningWarning(false);
              }}
            />
          </div>
        </form>
      </TooltipProvider>
    </FormProvider>
  );
};

export default Playground;
